class Solution:
    def minNumberOfHours(self, initialEnergy, initialExperience, energy, experience):
        need_energy = max(0, sum(energy) + 1 - initialEnergy)
        hours = need_energy
        x = initialExperience
        for ex in experience:
            if x <= ex:
                hours += ex + 1 - x
                x = ex + 1
            x += ex
        return hours

